{
  "category_name": "recon",
  "tool_name": "nmap",
  "tool_description": "Network discovery scanner",
  "tool_long_description": "Performs service detection and host discovery.",
  "examples": [
    {
      "command": "nmap -sV 10.0.0.1"
    }
  ],
  "input_schema": {
    "type": "object",
    "fields": [
      {
        "key": "target",
        "type": "string",
        "required": true,
        "flag": "-iL",
        "description": "Target host or file list"
      }
    ],
    "pipeline_input": {
      "multi_mode": "first",
      "target_field": "target"
    }
  },
  "output_schema": {
    "type": "jsonl",
    "description": "Structured scan results",
    "fields": [
      {
        "key": "host",
        "type": "string",
        "label": "Host",
        "finding_host": true
      },
      {
        "key": "port",
        "type": "integer",
        "label": "Port"
      },
      {
        "key": "service",
        "type": "string",
        "label": "Service"
      }
    ],
    "pipeline_output": {
      "mode": "jsonl",
      "entity": "result",
      "extract_field": "host",
      "dedupe": true
    }
  },
  "scan_config": {
    "basic": {
      "presets": [
        {
          "name": "default",
          "description": "Default scan",
          "flags": [
            "-sV"
          ]
        }
      ]
    },
    "medium": {
      "options": [
        {
          "flag": "-p",
          "key": "ports",
          "type": "string",
          "description": "Ports to scan"
        }
      ]
    },
    "advanced": {
      "options": [
        {
          "flag": "-sS",
          "key": "syn_scan",
          "type": "boolean",
          "description": "Enable SYN scan"
        }
      ]
    },
    "runtime": {
      "use_gvisor": true,
      "network_mode": "host",
      "privileged": false,
      "cap_add": [
        "NET_RAW"
      ]
    }
  },
  "install_method": "apt",
  "version": "7.94",
  "image_ref": "ghcr.io/nmap/nmap:latest",
  "image_source": "dockerhub",
  "build_config": {
    "dockerfile": "Dockerfile"
  },
  "is_active": true,
  "denied_options": [
    "--script",
    "--interactive"
  ],
  "shadow_output_config": {
    "preferred_format": "jsonl",
    "formats": {
      "jsonl": {
        "transport": "stdout",
        "enable_flags": [
          "-json"
        ],
        "parser": "jsonl",
        "path_mode": "streaming",
        "file_extension": ".jsonl"
      }
    },
    "default_path": "/tmp/shadow",
    "parse_timeout_seconds": 30,
    "fallback_to_stdout": true,
    "is_streaming": true,
    "alternative_formats": []
  },
  "parser_config": {
    "type": "jsonl",
    "field_mappings": {
      "title": [
        "service",
        "port"
      ],
      "severity": "medium",
      "host": [
        "host"
      ],
      "description": [
        "description"
      ],
      "metadata": [
        "raw"
      ]
    },
    "default_severity": "medium",
    "fingerprint_fields": [
      "host",
      "port"
    ],
    "interesting_rule": {
      "field": "severity",
      "condition": "gte",
      "value": "high"
    }
  }
}
